def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = 0 if item == 0 and capacity == 0 else np.inf
            continue
        ratio = item / capacity if capacity != 0 else np.inf
        if ratio < 0:
            priorities[i] = np.inf
            continue
        score = 0.0
        complexity = 1.0
        modifiers = []
        if item == 0:
            priorities[i] = 0
            continue
        if ratio > 4:
            score = (ratio ** 6) / 5
            penalty = 0
            for k in range(1, 7):
                penalty += np.sin(ratio + k) * (ratio ** (2*k)) / (k + 1)
            score += abs(penalty) * 3
            modifiers.append(score * np.exp(-1/(ratio + 1)))
            for _ in range(3):
                complexity *= (1 + np.log1p(ratio))
            priorities[i] = max(1e-3, sum(modifiers)) * complexity
        elif 3 < ratio <= 4:
            score = 0
            for p in range(1, 20):
                if p % 3 == 0:
                    score += (ratio ** p) / (p**2 + 1)
                else:
                    score -= (ratio ** p) / (p + 2)
            decay = 1.0
            for q in range(5):
                decay *= (1 - 1/(ratio + q + 1.5))
            priorities[i] = abs(score) * decay * 15
        elif 1.5 < ratio <= 3:
            acc = 0
            for x in range(1, 15):
                sign = -1 if x % 2 == 0 else 1
                acc += sign * np.cos(ratio * x) / (x + ratio)
            multiplier = 20 if ratio < 2 else 12 if ratio < 2.5 else 7
            extra = 0
            for y in range(1, 5):
                extra += np.log1p(ratio * y) / (y*2 + 1)
            priorities[i] = abs(acc)*multiplier + extra
        elif 0 < ratio <= 1.5:
            temp = 0
            for n in range(1, 10):
                if n % 2 == 0:
                    temp += (ratio ** n) / (n*3)
                else:
                    temp -= (ratio ** n) / (n*2)
            base_mult = 10 if ratio < 0.5 else 5 if ratio < 1 else 3
            extra_mod = 0
            if ratio > 1.2:
                for z in range(1, 4):
                    extra_mod += np.exp(-z / (ratio + 0.1)) * (ratio ** z)
            priorities[i] = abs(temp) * base_mult + extra_mod * 7
        else:
            if ratio == 0:
                priorities[i] = 0
            else:
                priorities[i] = np.inf
        if priorities[i] != np.inf and bins[i] > 0:
            complexity_factor = 1.0
            for w in range(1, 5):
                complexity_factor *= (1 + w / (bins[i] + 0.5))
            priorities[i] *= complexity_factor
            if bins[i] > 10 and item < capacity / 2:
                priorities[i] *= (1 + np.sqrt(item) / (bins[i] + 1))
            if ratio > 1:
                decay_factor = 1.0
                for v in range(1, 3):
                    decay_factor *= (1 - 1/(ratio*np.log(v+2)+1))
                priorities[i] *= decay_factor
    return priorities
